/// Check whether a parser is statically compiled into this build.
///
/// Returns `true` only when the grammar was compiled in at build time
/// (i.e. it appears in the `STATIC_LANGUAGES` table). This is independent
/// of the extension-to-language mapping: `detect_language_from_extension`
/// consults the static ext table for all 306 grammars regardless of which
/// parsers are compiled in.
///
/// Use this when you need to distinguish "we know the language name" from
/// "we can actually parse files in that language right now".
///
/// ```no_run
/// use tree_sitter_language_pack::{detect_language_from_extension, LanguageRegistry};
///
/// let registry = LanguageRegistry::new();
/// // Extension detection uses the static table — independent of compiled parsers.
/// let lang = detect_language_from_extension("feature"); // always returns Some("gherkin")
/// // Parser availability depends on which grammars were compiled in.
/// let can_parse = lang.map(|name| registry.has_parser(name)).unwrap_or(false);
/// ```
#[rustler::nif]
pub fn languageregistry_has_parser(resource: rustler::ResourceArc<LanguageRegistry>, name: String) -> bool {
    resource.inner.as_ref().has_parser(&name)
}

/// Check whether a language is available by name or alias.
///
/// Returns `true` if the language can be loaded, either from the static
/// table or from a dynamic library on disk.
#[rustler::nif]
pub fn languageregistry_has_language(resource: rustler::ResourceArc<LanguageRegistry>, name: String) -> bool {
    resource.inner.as_ref().has_language(&name)
}

/// Return the total number of available languages (including aliases).
#[rustler::nif]
pub fn languageregistry_language_count(resource: rustler::ResourceArc<LanguageRegistry>) -> usize {
    resource.inner.as_ref().language_count()
}

/// Parse source code and extract file intelligence based on config in a single pass.
#[rustler::nif]
pub fn languageregistry_process(
    resource: rustler::ResourceArc<LanguageRegistry>,
    source: String,
    config: Option<String>,
) -> Result<ProcessResult, String> {
    let config_core: Option<tree_sitter_language_pack::ProcessConfig> = config
        .map(|s| serde_json::from_str::<tree_sitter_language_pack::ProcessConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let result = resource
        .inner
        .as_ref()
        .process(&source, config_core.as_ref().unwrap_or(&Default::default()))
        .map_err(|e| e.to_string())?;
    Ok(result.into())
}

#[rustler::nif]
pub fn languageregistry_default() -> ResourceArc<LanguageRegistry> {
    ResourceArc::new(LanguageRegistry {
        inner: Arc::new(tree_sitter_language_pack::LanguageRegistry::default()),
    })
}

/// Create a new download manager for the given version.
#[rustler::nif]
pub fn downloadmanager_new(version: String) -> Result<ResourceArc<DownloadManager>, String> {
    let result = tree_sitter_language_pack::DownloadManager::new(&version).map_err(|e| e.to_string())?;
    Ok(ResourceArc::new(DownloadManager {
        inner: Arc::new(result),
    }))
}

/// List languages that are already downloaded and cached.
#[rustler::nif]
pub fn downloadmanager_installed_languages(resource: rustler::ResourceArc<DownloadManager>) -> Vec<String> {
    resource.inner.as_ref().installed_languages()
}

/// Download the platform bundle and extract every library file it contains.
///
/// Unlike [`Self::ensure_languages`], this does not check the manifest language list
/// against archive contents — it simply extracts all `.so`/`.dylib`/`.dll` files
/// from the bundle. Languages in the manifest that are missing from the archive
/// are silently ignored rather than returning an error.
///
/// Returns the number of library files extracted (including those already cached).
#[rustler::nif]
pub fn downloadmanager_download_all_best_effort(
    resource: rustler::ResourceArc<DownloadManager>,
) -> Result<usize, String> {
    let result = resource
        .inner
        .as_ref()
        .download_all_best_effort()
        .map_err(|e| e.to_string())?;
    Ok(result)
}

/// Remove all cached parser libraries.
///
/// Acquires the cross-process lock so `clean_cache` cannot race a concurrent
/// downloader (avoids Windows sharing-violation errors against an in-flight
/// bundle write). The `.download.lock` file itself is **not** removed — it is
/// permanent infrastructure; deleting it could allow a concurrent process that
/// already opened the file to continue holding a stale lock handle while a new
/// process opens a fresh inode, breaking the mutual-exclusion guarantee.
#[rustler::nif]
pub fn downloadmanager_clean_cache(resource: rustler::ResourceArc<DownloadManager>) -> Result<(), String> {
    let result = resource.inner.as_ref().clean_cache().map_err(|e| e.to_string())?;
    Ok(result)
}

